                                   $$, $$b2f880a629dda9aec78c26e1595538899fda9af365c0343b78e742c1198f5a37$$, $${"A": "1d3b78f8267a3a7fe43851080d28939f6879e07d2e9924a14881d4c6ca40d22b", "C": "d4fdf923ba776b98bda680220afe7660b2fb7f78e25f4cb026ad0b29031d9620", "D": "605ce9015d85d8bfed4605a4e4b15691dae3085470f23bad5b3781e778b53aaf"}$$::jsonb, $$Budget J-Books/FY26/Army/RDTE - Vol 3 - Budget Activity 5D.pdf$$, 141, $$2026-05-10T04:01:21.372876+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0605148A$$, 2026, $$The Tactical Intelligence Targeting Access Node (TITAN) is a key enabler of the Army Modernization Priorities in support of Army Cross Functional Teams. TITAN is a
scalable and expeditionary intelligence ground station that supports commanders across the entire Multi-Domain Operations (MDO)/Joint All Domain Operations (JADO)
battlefield framework with capabilities tailored to echelon. TITAN leverages Space, High Altitude, Aerial and Terrestrial layer sensors to provide targetable data to fires
networks as well as multi-discipline intelligence support to targeting and Situation Awareness/Situation Understanding (SA/SU) in support of mission command. TITAN
will support Artificial Intelligence/Machine Learning (AI/ML) tools through Project Linchpin and other government sources and leverage Critical Radio Frequency (RF)
technologies as they become available.

 TITAN is the Army Intelligence, Surveillance, and Reconnaissance (ISR) ground station that consolidates the sensor processing capabilities in the current Distributed
 Common Ground System-Army (DCGS-A) Operational-Intelligence Ground Station (OGS), Tactical-Intelligence Ground Station (TGS), the Advanced Miniaturized Data
 Acquisition System Dissemination Vehicle (ADV) and the Remote Ground Terminal (RGT). Additionally, TITAN will access sensor data of Tactical Space Layer assets,
 National assets, the Multi-Domain Sensing Systems (MDSS) as well as commercial overhead sensors. Consequently, the TITAN ground station conducts deep sensing
 operations with the abilities to Task, Collect, Process, Exploit, and Disseminate (TCPED) information from Space, High Altitude, Aerial, and Terrestrial Layer sensors in
 support of Long Range Precision Fires (LRPF) operations.

 The FY 2026 cost of the Titan Intelligence Targeting Access Node (TITAN) Middle Tier of Acquisition effort is $23.7 million, including RDT&E and procurement of
 prototype units. The Department will certify FYDP funding in a future budget submission.
Development & Demonstration (SDD)$$, $$TITAN directly addresses the U.S. Army Combined Arms Center's (USACAC) Multi-Domain Operations (MDO) gap #1: Lack of echelons above corps (EAC) multi-
domain deep sensing, analysis, and processing, exploitation and dissemination (PED) for indications & warning (I&W) and anti-access/area denial (A2/AD) targeting.
Furthermore, TITAN indirectly addresses MDO Gap 2: No theater detect, decide, deliver, assess (D3A) and convergence of Long Range Precision Fires (LRPF) to
disintegrate A2/AD and MDO Gap #3: Lack of EAC LRPF capacity to disintegrate A2/AD and shape the deep fight. TITAN supports these MDO gaps by providing the
sensor data receipt and control, analysis, exploitation, and dissemination functions needed to enable LRPF.

 The FY26 RDTE Dollars in the amount of $44.273M will fund the completion of Development, Integration, and Testing of production-representative TITAN prototype
 systems. Funding will integrate high altitude, aerial and terrestrial sensor data feeds. Funding will integrate TENCAP-developed Space-Ground Component Kit (SGCK).
 Resources fund updates, integration, accreditation, & testing of new capabilities resulting from new sensor feeds and emerging technologies. Support includes
 Developmental and Soldier touchpoints to test-fix-test capabilities. Funding will also support initiation/execution of the Software Acquisition Pathway (SWP) and the
 continued development of the TITAN SW Baseline.

 The FY 2026 cost of the Titan Intelligence Targeting Access Node (TITAN) Middle Tier of Acquisition effort is $23.7 million, including RDT&E and procurement of
 prototype units. The Department will certify FYDP funding in a future budget submission.

